<script>
	import { ref, computed, onMounted } from 'vue'
	import { useUserStore } from '@/store/user'
	import { useDisputeStore } from '@/store/dispute'
		export default {
		setup() {
			const userStore = useUserStore()
			const disputeStore = useDisputeStore()
			
			const isLoading = ref(false)
			const statistics = ref({
				todayNew: 0,
				pendingAssign: 0,
				pendingVisit: 0,
				pendingPolice: 0,
				resolved: 0,
				resolveRate: '0.0',
				totalCount: 0,
				userCount: 0
			})
			const recentDisputes = ref([])
			const startDate = ref('')
			const endDate = ref('')
			const statusOptions = ['全部', '待分派', '待回访', '处理中', '已化解', '已关闭']
			const statusIndex = ref(0)
			
			// 计算属性
			const userInfo = computed(() => userStore.userInfo)
			const isPolice = computed(() => userStore.role === 'police')
			const isStreet = computed(() => userStore.role === 'street')
			const isCommunity = computed(() => userStore.role === 'community')
			const isAdmin = computed(() => userStore.role === 'admin')
			
			// 方法
			const goToInput = () => {
				uni.navigateTo({
					url: '/pages/input/index'
				})
			}
			
			const goToStreetManage = () => {
				uni.switchTab({
					url: '/pages/street/index'
				})
			}
			
			const goToDetail = (id) => {
				uni.navigateTo({
					url: `/pages/detail/index?id=${id}`
				})
			}
			
			const goToUserManage = () => {
				uni.navigateTo({
					url: '/pages/admin/user-list'
				})
			}
			
			const formatTime = (time) => {
				if (!time) return ''
				const date = new Date(time)
				return `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}-${String(date.getDate()).padStart(2, '0')} ${String(date.getHours()).padStart(2, '0')}:${String(date.getMinutes()).padStart(2, '0')}`
			}
			
			const onStartDateChange = (e) => {
				startDate.value = e.detail.value
				if (endDate.value && endDate.value < startDate.value) {
					endDate.value = ''
				}
			}
			
			const onEndDateChange = (e) => {
				endDate.value = e.detail.value
				if (startDate.value && endDate.value < startDate.value) {
					const temp = startDate.value
					startDate.value = endDate.value
					endDate.value = temp
				}
			}
			
			const onStatusChange = (e) => {
				statusIndex.value = Number(e.detail.value) || 0
			}
			
			const resetForm = () => {
				startDate.value = ''
				endDate.value = ''
			}
			
			const exportData = async () => {
				if (!userStore.isAdmin) return
				
				try {
					uni.showLoading({
						title: '正在导出...'
					})
					
					const pageSize = 100
					let page = 1
					const allData = []
					const status = statusOptions[statusIndex.value]
					const statusFilter = status === '全部' ? '' : status
					
					// 分批获取数据
					while (true) {
						const res = await uniCloud.callFunction({
							name: 'getDisputeList',
							data: {
								role: userStore.role,
								community: userStore.community,
								status: statusFilter,
								startDate: startDate.value,
								endDate: endDate.value,
								page: page,
								pageSize: pageSize,
								needTotal: false
							}
						})
						
						if (!res.result || !res.result.success) {
							throw new Error('获取数据失败')
						}
						
						const data = res.result.data || []
						allData.push(...data)
						
						if (!res.result.hasMore || data.length < pageSize) {
							break
						}
						
						page++
					}
					
					if (allData.length === 0) {
						uni.hideLoading()
						uni.showToast({
							title: '暂无数据可导出',
							icon: 'none'
						})
						return
					}
					
					// 生成CSV
					const headers = ['纠纷ID', '标题', '来源', '状态', '紧急度', '发生次数', '涉及人员', '地址', '创建时间', '分派社区ID', '分派时间']
					const rows = allData.map(item => {
						const createTime = item.create_time ? new Date(item.create_time) : null
						const assignTime = item.assign_time ? new Date(item.assign_time) : null
						
						const formatDate = (date) => {
							if (!date) return ''
							return `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}-${String(date.getDate()).padStart(2, '0')} ${String(date.getHours()).padStart(2, '0')}:${String(date.getMinutes()).padStart(2, '0')}:${String(date.getSeconds()).padStart(2, '0')}`
						}
						
						const formatNumber = (num) => {
							if (num == null) return ''
							return String(num)
						}
						
						return [
							item._id || '',
							`"${item.title || ''}"`,
							item.source || '',
							item.status || '',
							item.urgency || '',
							formatNumber(item.occur_count || 1),
							`"${item.parties || ''}"`,
							`"${item.location?.address || ''}"`,
							formatDate(createTime),
							item.assign_community_id || '',
							formatDate(assignTime)
						]
					})
					
					const csvContent = [
						headers.join(','),
						...rows.map(row => row.join(','))
					].join('\n')
					
					// 导出文件
					const fileName = `纠纷数据_${new Date().toISOString().split('T')[0]}.csv`
					
					if (uni.saveFile) {
						// 小程序环境
						const tempFilePath = `${wx.env.USER_DATA_PATH}/${fileName}`
						wx.writeFile({
							filePath: tempFilePath,
							data: csvContent,
							encoding: 'utf8',
							success: (res) => {
								uni.hideLoading()
								uni.showToast({
									title: '导出成功',
									icon: 'success'
								})
								
								// 打开文件
								wx.openDocument({
									filePath: res.savedFilePath
								})
							},
							fail: (err) => {
								uni.hideLoading()
								uni.showToast({
									title: '导出失败',
									icon: 'none'
								})
								console.error('导出失败', err)
							}
						})
					} else {
						// H5环境
						const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' })
						const link = document.createElement('a')
						const url = URL.createObjectURL(blob)
						link.setAttribute('href', url)
						link.setAttribute('download', fileName)
						link.style.visibility = 'hidden'
						document.body.appendChild(link)
						link.click()
						document.body.removeChild(link)
						uni.hideLoading()
						uni.showToast({
							title: '导出成功',
							icon: 'success'
						})
					}
				} catch (error) {
					uni.hideLoading()
					uni.showToast({
						title: '导出失败',
						icon: 'none'
					})
					console.error('导出失败', error)
				}
			}
			
			const loadStatistics = async () => {
				if (!userStore.userInfo) return
				
				try {
					isLoading.value = true
					
					const res = await uniCloud.callFunction({
						name: 'getStatistics',
						data: {
							role: userStore.role,
							community: userStore.community
						}
					})
					
					if (res.result && res.result.success) {
						statistics.value = {
							...statistics.value,
							...res.result.data
						}
					}
				} catch (error) {
					console.error('获取统计数据失败', error)
				} finally {
					isLoading.value = false
				}
			}
			
			const loadRecentDisputes = async () => {
				if (!userStore.userInfo) return
				
				try {
					isLoading.value = true
					
					const res = await uniCloud.callFunction({
						name: 'getDisputeList',
						data: {
							role: userStore.role,
							community: userStore.community,
							page: 1,
							pageSize: 10,
							needTotal: false
						}
					})
					
					if (res.result && res.result.success) {
						recentDisputes.value = (res.result.data || []).map(item => ({
							...item,
							statusClass: {
								'待分派': 'pending',
								'待回访': 'pending',
								'处理中': 'processing',
								'已化解': 'resolved',
								'已关闭': 'closed'
							}[item.status] || ''
						}))
					}
				} catch (error) {
					console.error('获取最近纠纷失败', error)
				} finally {
					isLoading.value = false
				}
			}
			
			// 生命周期
			onMounted(() => {
				loadStatistics()
				loadRecentDisputes()
			})
			
			return {
				userInfo,
				isPolice,
				isStreet,
				isCommunity,
				isAdmin,
				isLoading,
				statistics,
				recentDisputes,
				startDate,
				endDate,
				statusOptions,
				statusIndex,
				goToInput,
				goToStreetManage,
				goToDetail,
				goToUserManage,
				formatTime,
				onStartDateChange,
				onEndDateChange,
				onStatusChange,
				resetForm,
				exportData
			}
		}
	}
</script>

